import react, {useEffect, useState} from "react";
import cardService from "../services/cardService";

type Card = {
    id: number;
    title: string;
    body: string;
    userId: number;
}

const PostEditor: React.FC = () => {
    const [posts, setPosts] = useState<Post[]>([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);
    const [page, setPage] = useState(1);
    const limit = 4;

    // Form state for new/edit post
    const [editingPost, setEditingPost] = useState<Post | null>(null);
    const [formTitle, setFormTitle] = useState("");
    const [formBody, setFormBody] = useState("");
    const [formUserId, setFormUserId] = useState<string>("1");
    const [isCreating, setIsCreating] = useState(false);

    const loadPosts = async () => {
        try {
            setLoading(true);
            setError(null);
            const data = await postService.getPosts<Post[]>(page, limit);
            if (data) {
                setPosts(data);
            }
        } catch (err: any) {
            setError(err.message || "Failed to load posts");
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        loadPosts();
    }, [page]);

    const handleCreate = async () => {
        try {
            setLoading(true);
            const newPost = {
                title: formTitle,
                body: formBody,
                userId: parseInt(formUserId) || 1,
            };
            const created = await postService.createPost<Post>(newPost);
            if (created) {
                alert(`Post created (POST) successfully with received ID: ${created.id}. Note: API does not persist data.`);
                setFormTitle("");
                setFormBody("");
                setFormUserId("1");
                setIsCreating(false);
                // Refresh or just let the user know it was sent
                await loadPosts();
            }
        } catch (err: any) {
            setError(err.message || "Failed to create post");
        } finally {
            setLoading(false);
        }
    };

    const handleUpdate = async (method: "PUT" | "PATCH") => {
        if (!editingPost) return;
        try {
            setLoading(true);
            let updated: Post | undefined;
            if (method === "PUT") {
                updated = await postService.replacePost<Post>(editingPost.id, {
                    ...editingPost,
                    title: formTitle,
                    body: formBody,
                    userId: parseInt(formUserId) || editingPost.userId
                });
            } else {
                updated = await postService.updatePost<Post>(editingPost.id, {
                    title: formTitle
                });
            }

            if (updated) {
                alert(`Post ${method === "PUT" ? "replaced" : "updated"} successfully!`);

                // Update local state instead of re-fetching from mock API
                setPosts(prevPosts => prevPosts.map(p => p.id === updated!.id ? updated! : p));

                setEditingPost(null);
                setFormTitle("");
                setFormBody("");
                setFormUserId("1");
            }
        } catch (err: any) {
            setError(err.message || "Failed to update post");
        } finally {
            setLoading(false);
        }
    };

    const handleDelete = async (id: number) => {
        if (!window.confirm("Are you sure you want to delete this post?")) return;
        try {
            setLoading(true);
            await postService.deletePost(id);

            // JSONPlaceholder doesn't persist deletes, so we must update local state
            setPosts(prevPosts => prevPosts.filter(post => post.id !== id));

            alert("Post deleted successfully (DELETE)!");
            // No need to call loadPosts() as it would fetch the old data from mock API
        } catch (err: any) {
            setError(err.message || "Failed to delete post");
        } finally {
            setLoading(false);
        }
    };

    const startEditing = (post: Post) => {
        setEditingPost(post);
        setFormTitle(post.title);
        setFormBody(post.body);
        setFormUserId(post.userId.toString());
        setIsCreating(false);
    };

    const startCreating = () => {
        setIsCreating(true);
        setEditingPost(null);
        setFormTitle("");
        setFormBody("");
        setFormUserId("1");
    };

    if (loading && posts.length === 0) return <div style={{ textAlign: "center", padding: 50 }}>Loading posts...</div>;

    return (
        <div style={{ maxWidth: 800, margin: "0 auto", fontFamily: "Inter, sans-serif", color: "#333" }}>
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 20 }}>
                <h2>Post Editor (Page {page})</h2>
                <button
                    onClick={startCreating}
                    style={{ padding: "8px 16px", backgroundColor: "#4CAF50", color: "white", border: "none", borderRadius: 4, cursor: "pointer" }}
                >
                    + New Post
                </button>
            </div>

            {error && <div style={{ color: "red", padding: 10, background: "#fee", borderRadius: 4, marginBottom: 20 }}>{error}</div>}

            {(isCreating || editingPost) && (
                <div style={{ background: "#f9f9f9", padding: 20, borderRadius: 8, marginBottom: 30, border: "1px solid #ddd" }}>
                    <h3>{isCreating ? "Create New Post" : `Edit Post #${editingPost?.id}`}</h3>
                    <div style={{ marginBottom: 10 }}>
                        <label style={{ display: "block", marginBottom: 5 }}>User ID</label>
                        <input
                            type="number"
                            value={formUserId}
                            onChange={(e) => setFormUserId(e.target.value)}
                            style={{ width: "100%", padding: 8, borderRadius: 4, border: "1px solid #ccc" }}
                        />
                    </div>
                    <div style={{ marginBottom: 10 }}>
                        <label style={{ display: "block", marginBottom: 5 }}>Title</label>
                        <input
                            value={formTitle}
                            onChange={(e) => setFormTitle(e.target.value)}
                            style={{ width: "100%", padding: 8, borderRadius: 4, border: "1px solid #ccc" }}
                        />
                    </div>
                    <div style={{ marginBottom: 10 }}>
                        <label style={{ display: "block", marginBottom: 5 }}>Body</label>
                        <textarea
                            value={formBody}
                            onChange={(e) => setFormBody(e.target.value)}
                            style={{ width: "100%", padding: 8, borderRadius: 4, border: "1px solid #ccc", minHeight: 80 }}
                        />
                    </div>
                    <div style={{ display: "flex", gap: 10 }}>
                        {isCreating ? (
                            <button onClick={handleCreate} style={{ padding: "8px 16px", backgroundColor: "#2196F3", color: "white", border: "none", borderRadius: 4, cursor: "pointer" }}>Create (POST)</button>
                        ) : (
                            <>
                                <button onClick={() => handleUpdate("PUT")} style={{ padding: "8px 16px", backgroundColor: "#2196F3", color: "white", border: "none", borderRadius: 4, cursor: "pointer" }}>Replace (PUT)</button>
                                <button onClick={() => handleUpdate("PATCH")} style={{ padding: "8px 16px", backgroundColor: "#FF9800", color: "white", border: "none", borderRadius: 4, cursor: "pointer" }}>Update Title (PATCH)</button>
                            </>
                        )}
                        <button onClick={() => { setIsCreating(false); setEditingPost(null); }} style={{ padding: "8px 16px", background: "#eee", border: "none", borderRadius: 4, cursor: "pointer" }}>Cancel</button>
                    </div>
                </div>
            )}

            <div style={{ display: "grid", gridTemplateColumns: "1fr", gap: 20 }}>
                {posts.map(post => (
                    <div key={post.id} style={{
                        padding: "20px",
                        border: "1px solid #e0e0e0",
                        borderRadius: "12px",
                        background: "white",
                        boxShadow: "0 4px 6px rgba(0,0,0,0.02)",
                        transition: "transform 0.2s ease, box-shadow 0.2s ease",
                    }}>
                        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 12 }}>
                            <h4 style={{ margin: 0, color: "#1a1a1a", fontSize: "1.1rem", fontWeight: 600 }}>{post.title}</h4>
                            <span style={{ fontSize: "0.75rem", color: "#999", background: "#f5f5f5", padding: "2px 8px", borderRadius: 4 }}>ID: {post.id}</span>
                        </div>
                        <p style={{ fontSize: "0.95rem", color: "#444", lineHeight: "1.5", marginBottom: 20 }}>{post.body}</p>
                        <div style={{ display: "flex", gap: 12, borderTop: "1px solid #f0f0f0", paddingTop: 15 }}>
                            <button
                                onClick={() => startEditing(post)}
                                style={{
                                    fontSize: "0.85rem",
                                    padding: "6px 16px",
                                    background: "#f0f7ff",
                                    color: "#0066cc",
                                    border: "1px solid #cce3ff",
                                    borderRadius: 6,
                                    cursor: "pointer",
                                    fontWeight: 500
                                }}
                            >
                                Edit Post
                            </button>
                            <button
                                onClick={() => handleDelete(post.id)}
                                style={{
                                    fontSize: "0.85rem",
                                    padding: "6px 16px",
                                    background: "#fff5f5",
                                    color: "#cc0000",
                                    border: "1px solid #ffebeb",
                                    borderRadius: 6,
                                    cursor: "pointer",
                                    fontWeight: 500
                                }}
                            >
                                Delete
                            </button>
                        </div>
                    </div>
                ))}
            </div>

            <div style={{ display: "flex", justifyContent: "center", alignItems: "center", gap: 20, marginTop: 30 }}>
                <button
                    disabled={page === 1}
                    onClick={() => setPage(p => p - 1)}
                    style={{ padding: "8px 16px", borderRadius: 4, border: "1px solid #ccc", cursor: page === 1 ? "not-allowed" : "pointer", background: page === 1 ? "#f5f5f5" : "white" }}
                >
                    Previous
                </button>
                <span>Page {page}</span>
                <button
                    onClick={() => setPage(p => p + 1)}
                    style={{ padding: "8px 16px", borderRadius: 4, border: "1px solid #ccc", cursor: "pointer", background: "white" }}
                >
                    Next
                </button>
            </div>
        </div>
    );
};

export default PostEditor;









